1	const PROCESSING_FEE = 5;
2	const DEDUCTIBLE = 100;
3	const CAP_MULTIPLIER = 2;
4	
5	type ItemCatalogEntry = { basePremium: number; insuranceValue: number };
6	
7	const ITEM_CATALOG: Record<string, ItemCatalogEntry> = {
8	  sword:     { basePremium: 100, insuranceValue: 1000 },
9	  amulet:    { basePremium:  60, insuranceValue:  600 },
10	  staff:     { basePremium:  80, insuranceValue:  800 },
11	  potion:    { basePremium:  40, insuranceValue:  400 },
12	  rune:      { basePremium:  25, insuranceValue:  250 },
13	  moonstone: { basePremium:  25, insuranceValue:  250 },
14	};
15	
16	type Item = { type: string; material?: string; enchantment?: number; cursed?: boolean };
17	type Customer = { yearsWithMHPCO: number };
18	type QuoteStep = { op: "quote"; items: Item[] };
19	type Damage = { itemType: string; amount: number };
20	type Incident = { cause: string; damages: Damage[] };
21	type ClaimStep = { op: "claim"; policy: number; incident: Incident };
22	type Step = QuoteStep | ClaimStep;
23	type Scenario = { customer: Customer; steps: Step[] };
24	
25	const basePremiumFor = (item: Item): number => ITEM_CATALOG[item.type].basePremium;
26	
27	const COMPONENT_BLOCK_SIZE = 3;
28	const COMPONENT_BLOCK_PREMIUM = 60;
29	
30	const sumBy = <T>(xs: T[], f: (x: T) => number): number =>
31	  xs.reduce((sum, x) => sum + f(x), 0);
32	
33	const groupBy = <T>(xs: T[], key: (x: T) => string): Map<string, T[]> => {
34	  const groups = new Map<string, T[]>();
35	  for (const x of xs) {
36	    const k = key(x);
37	    const group = groups.get(k) ?? [];
38	    group.push(x);
39	    groups.set(k, group);
40	  }
41	  return groups;
42	};
43	
44	const groupByType = (items: Item[]): Item[][] =>
45	  [...groupBy(items, (i) => i.type).values()];
46	
47	const basePremiumForGroup = (group: Item[]): number =>
48	  group.length === COMPONENT_BLOCK_SIZE
49	    ? COMPONENT_BLOCK_PREMIUM
50	    : sumBy(group, basePremiumFor);
51	
52	const totalBasePremium = (items: Item[]): number =>
53	  sumBy(groupByType(items), basePremiumForGroup);
54	
55	const CURSE_SURCHARGE_RATE = 0.5;
56	const HIGH_ENCHANTMENT_RATE = 0.3;
57	const HIGH_ENCHANTMENT_THRESHOLD = 5;
58	const FIRST_INSURANCE_RATE = 0.1;
59	const LOYALTY_DISCOUNT_RATE = -0.2;
60	const LOYALTY_YEARS_THRESHOLD = 2;
61	const FOLLOW_UP_DISCOUNT_RATE = -0.15;
62	
63	type PolicyContext = { customer: Customer; isFollowUp: boolean };
64	
65	const isCursed = (item: Item): boolean => item.cursed === true;
66	const enchantmentLevel = (item: Item): number => item.enchantment ?? 0;
67	const isHighlyEnchanted = (item: Item): boolean =>
68	  enchantmentLevel(item) >= HIGH_ENCHANTMENT_THRESHOLD;
69	
70	type Modifier<T> = { applies: (subject: T) => boolean; rate: number };
71	
72	const sumApplicableRates = <T>(modifiers: Modifier<T>[], subject: T): number =>
73	  sumBy(modifiers, ({ applies, rate }) => (applies(subject) ? rate : 0));
74	
75	const ITEM_SURCHARGES: Modifier<Item>[] = [
76	  { applies: isCursed, rate: CURSE_SURCHARGE_RATE },
77	  { applies: isHighlyEnchanted, rate: HIGH_ENCHANTMENT_RATE },
78	];
79	
80	const isLoyalCustomer = (ctx: PolicyContext): boolean =>
81	  ctx.customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD;
82	const isFollowUpContract = (ctx: PolicyContext): boolean => ctx.isFollowUp;
83	
84	// First-insurance rate applies to every quote unconditionally;
85	// other policy modifiers are conditional on the customer/contract context.
86	const POLICY_MODIFIERS: Modifier<PolicyContext>[] = [
87	  { applies: isLoyalCustomer, rate: LOYALTY_DISCOUNT_RATE },
88	  { applies: isFollowUpContract, rate: FOLLOW_UP_DISCOUNT_RATE },
89	];
90	
91	const policyAdjustment = (baseTotal: number, ctx: PolicyContext): number =>
92	  baseTotal * (FIRST_INSURANCE_RATE + sumApplicableRates(POLICY_MODIFIERS, ctx));
93	
94	const itemSurchargeFor = (item: Item): number =>
95	  basePremiumFor(item) * sumApplicableRates(ITEM_SURCHARGES, item);
96	
97	const itemSurchargesTotal = (items: Item[]): number =>
98	  sumBy(items, itemSurchargeFor);
99	
100	// MHPCO always rounds in its own favor: premiums round UP (customer pays more),
101	// payouts round DOWN (customer receives less).
102	const roundPremiumInOfficesFavor = Math.ceil;
103	const roundPayoutInOfficesFavor = Math.floor;
104	
105	const premiumFor = (items: Item[], ctx: PolicyContext): number => {
106	  const baseTotal = totalBasePremium(items);
107	  return roundPremiumInOfficesFavor(
108	    baseTotal +
109	      itemSurchargesTotal(items) +
110	      policyAdjustment(baseTotal, ctx) +
111	      PROCESSING_FEE,
112	  );
113	};
114	
115	const insuranceValueFor = (item: Item): number => ITEM_CATALOG[item.type].insuranceValue;
116	
117	const insuranceSumFor = (items: Item[]): number => sumBy(items, insuranceValueFor);
118	
119	const HIGH_ENCHANTMENT_CLAIM_THRESHOLD = 8;
120	const HIGH_ENCHANTMENT_REIMBURSEMENT_RATE = 0.5;
121	
122	const triggersHighEnchantmentClause = (item: Item): boolean =>
123	  enchantmentLevel(item) >= HIGH_ENCHANTMENT_CLAIM_THRESHOLD;
124	
125	const reimbursableAmount = (damage: Damage, item: Item): number =>
126	  triggersHighEnchantmentClause(item)
127	    ? damage.amount * HIGH_ENCHANTMENT_REIMBURSEMENT_RATE
128	    : damage.amount;
129	
130	const payoutForDamage = (damage: Damage, item: Item): number =>
131	  reimbursableAmount(damage, item) - DEDUCTIBLE;
132	
133	const policyItemFor = (policy: QuoteStep, damage: Damage): Item =>
134	  policy.items.find((item) => item.type === damage.itemType)!;
135	
136	const capFor = (items: Item[]): number =>
137	  insuranceSumFor(items) * CAP_MULTIPLIER;
138	
139	const countBy = <T>(xs: T[], key: (x: T) => string): Map<string, number> => {
140	  const counts = new Map<string, number>();
141	  for (const x of xs) {
142	    const k = key(x);
143	    counts.set(k, (counts.get(k) ?? 0) + 1);
144	  }
145	  return counts;
146	};
147	
148	const validateDamageCounts = (damages: Damage[], items: Item[]): void => {
149	  const itemCounts = countBy(items, (i) => i.type);
150	  const damageCounts = countBy(damages, (d) => d.itemType);
151	  for (const [type, count] of damageCounts) {
152	    if (count > (itemCounts.get(type) ?? 0)) {
153	      throw new Error(`claim references more ${type} damages than the policy covers`);
154	    }
155	  }
156	};
157	
158	const claimResultFor = (
159	  step: ClaimStep,
160	  policy: QuoteStep,
161	  alreadyConsumed: number,
162	): { payout: number; remainingCap: number } => {
163	  const { damages } = step.incident;
164	  const { items } = policy;
165	  validateDamageCounts(damages, items);
166	  const desired = sumBy(damages, (damage) =>
167	    payoutForDamage(damage, policyItemFor(policy, damage)),
168	  );
169	  const remainingBefore = capFor(items) - alreadyConsumed;
170	  const payout = roundPayoutInOfficesFavor(Math.min(desired, remainingBefore));
171	  return { payout, remainingCap: remainingBefore - payout };
172	};
173	
174	const quoteResultFor = (step: QuoteStep, ctx: PolicyContext) => ({
175	  premium: premiumFor(step.items, ctx),
176	});
177	
178	const policyContextFor = (scenario: Scenario, stepIndex: number): PolicyContext => ({
179	  customer: scenario.customer,
180	  isFollowUp: stepIndex > 0,
181	});
182	
183	const policyReferencedBy = (scenario: Scenario, claim: ClaimStep): QuoteStep =>
184	  scenario.steps[claim.policy] as QuoteStep;
185	
186	export const runScenario = (input: unknown): unknown => {
187	  const scenario = input as Scenario;
188	  const consumedCapByPolicy = new Map<number, number>();
189	  const results = scenario.steps.map((step, stepIndex) => {
190	    if (step.op === "quote") {
191	      return quoteResultFor(step, policyContextFor(scenario, stepIndex));
192	    }
193	    const policy = policyReferencedBy(scenario, step);
194	    const alreadyConsumed = consumedCapByPolicy.get(step.policy) ?? 0;
195	    const result = claimResultFor(step, policy, alreadyConsumed);
196	    consumedCapByPolicy.set(step.policy, alreadyConsumed + result.payout);
197	    return result;
198	  });
199	  return { results };
200	};
